static int constant_time_compare(const uint8_t *a, const uint8_t *b, uint32_t len)
{
    volatile uint8_t diff = 0;
    uint32_t i;
    for (i = 0; i < len; i++) {
        diff |= a[i] ^ b[i];
    }
    return (diff == 0) ? 1 : 0;
}

/* ---------- Secure memory zeroing ---------- */

static void secure_memzero(void *ptr, size_t len)
{
    volatile uint8_t *p = (volatile uint8_t *)ptr;
    while (len--) {
        *p++ = 0;
    }
}

